const BASE='https://services.leadconnectorhq.com';
const TOKEN=process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB||process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const LOCATION='TW8JsPW5NMnA3tfK2XLn';
if(!TOKEN){console.log(JSON.stringify({error:'missing_token'}));process.exit(0)}
const headers={Authorization:`Bearer ${TOKEN}`,Version:'2021-07-28',Accept:'application/json','Content-Type':'application/json'};
const now=Date.now();
const DAY=24*60*60*1000;

const toArr=(x)=>Array.isArray(x)?x:[];
const toMs=(v)=>{if(v==null)return 0;const n=Number(v);if(Number.isFinite(n)&&n>0)return n<1e12?n*1000:n;const d=Date.parse(v);return Number.isFinite(d)?d:0};
const pct=(a,b)=>b?+(a*100/b).toFixed(2):0;

async function req(path){
 const r=await fetch(BASE+path,{headers});
 const t=await r.text();
 let j={}; try{j=t?JSON.parse(t):{}}catch{j={raw:t}};
 return {ok:r.ok,status:r.status,body:j};
}

async function getAll(endpoint, key){
 let page=1, out=[];
 while(page<=10){
   const sep=endpoint.includes('?')?'&':'?';
   const r=await req(`${endpoint}${sep}limit=100&page=${page}`);
   if(!r.ok) break;
   const arr=toArr(r.body[key]||r.body.data?.[key]||r.body.data);
   out.push(...arr);
   if(arr.length<100) break;
   page++;
 }
 return out;
}

(async()=>{
 const [opps,convs,contacts,calRes]=await Promise.all([
   getAll(`/opportunities/search?location_id=${LOCATION}`,'opportunities'),
   getAll(`/conversations/search?locationId=${LOCATION}`,'conversations'),
   getAll(`/contacts/?locationId=${LOCATION}`,'contacts'),
   req(`/calendars/?locationId=${LOCATION}`)
 ]);

 // booked calls (last 24h)
 let bookedCalls24h=0;
 const calendars=toArr(calRes.body.calendars||calRes.body.data?.calendars||calRes.body.data);
 if(calendars[0]?.id){
   const start=new Date(now-DAY).toISOString();
   const end=new Date(now).toISOString();
   const ev=await req(`/calendars/events?locationId=${LOCATION}&calendarId=${calendars[0].id}&startTime=${encodeURIComponent(start)}&endTime=${encodeURIComponent(end)}`);
   const events=toArr(ev.body.events||ev.body.data?.events||ev.body.data);
   bookedCalls24h=events.filter(e=>String(e.status||'').toLowerCase()!=='cancelled').length;
 }

 // speed-to-lead from conversation message history: first outbound - first inbound
 const slas=[];
 let followupDue=0, followupMet=0;
 let complaintSignals=0, refundSignals=0, fulfillmentFailures=0;
 const complaintRx=/\b(complaint|angry|frustrated|bad service|terrible)\b/i;
 const refundRx=/\b(refund|chargeback|dispute|money back|cancel and refund)\b/i;
 const fulfillRx=/\b(didn'?t receive|not received|cannot access|can'?t access|login issue|link (is )?not working|didn'?t get)\b/i;

 for(const c of convs){
   const msgRes=await req(`/conversations/${c.id}/messages?limit=100`);
   const msgs=toArr(msgRes.body.messages?.messages||msgRes.body.messages||msgRes.body.data?.messages||msgRes.body.data).sort((a,b)=>toMs(a.dateAdded)-toMs(b.dateAdded));
   if(!msgs.length) continue;
   const firstInbound=msgs.find(m=>String(m.direction||'').toLowerCase()==='inbound');
   if(firstInbound){
     const inMs=toMs(firstInbound.dateAdded);
     const outAfter=msgs.find(m=>String(m.direction||'').toLowerCase()==='outbound' && toMs(m.dateAdded)>=inMs);
     if(outAfter){
       const deltaMin=(toMs(outAfter.dateAdded)-inMs)/60000;
       if(deltaMin>=0 && deltaMin<60*24*14) slas.push(deltaMin);
     }
   }
   const lastInbound=(()=>{for(let i=msgs.length-1;i>=0;i--){if(String(msgs[i].direction||'').toLowerCase()==='inbound') return msgs[i];}return null;})();
   if(lastInbound){
     const inMs=toMs(lastInbound.dateAdded);
     if(now-inMs>10*60*1000){
       followupDue++;
       const hasAfter=msgs.some(m=>String(m.direction||'').toLowerCase()==='outbound' && toMs(m.dateAdded)>inMs);
       if(hasAfter) followupMet++;
     }
   }
   for(const m of msgs){
     const ms=toMs(m.dateAdded); if(!ms||now-ms>7*DAY) continue;
     const txt=String(m.body||'');
     if(refundRx.test(txt)) refundSignals++;
     if(complaintRx.test(txt)) complaintSignals++;
     if(fulfillRx.test(txt)) fulfillmentFailures++;
   }
 }

 slas.sort((a,b)=>a-b);
 const median=slas.length?slas[Math.floor((slas.length-1)/2)]:null;
 const p95=slas.length?slas[Math.min(slas.length-1,Math.ceil(slas.length*0.95)-1)]:null;

 // stale leads >24h + stage aging outliers
 const openOpps=opps.filter(o=>!['won','lost','abandoned'].includes(String(o.status||'').toLowerCase()));
 const ageHours=(o)=>{
   const ms=toMs(o.lastActivityDate||o.lastStatusChangeAt||o.lastStageChangeAt||o.updatedAt||o.createdAt);
   return ms?((now-ms)/3600000):0;
 };
 const stale24=openOpps.filter(o=>ageHours(o)>24).length;
 const stageOutliers=openOpps.filter(o=>{
   const ms=toMs(o.lastStageChangeAt||o.lastStatusChangeAt||o.updatedAt||o.createdAt);
   return ms && (now-ms)>7*DAY;
 }).length;

 const followupCompletion=followupDue?+(100*followupMet/followupDue).toFixed(2):100;
 const optOutCount=contacts.filter(c=>c.dnd===true||String(c.dnd||'').toLowerCase()==='true').length;
 const optOutRate=pct(optOutCount,contacts.length);

 const metrics={
   booked_calls_24h:bookedCalls24h,
   speed_to_lead_median_min:median==null?null:+median.toFixed(2),
   speed_to_lead_p95_min:p95==null?null:+p95.toFixed(2),
   stale_leads_gt24h:stale24,
   follow_up_completion_rate_pct:followupCompletion,
   stage_aging_outliers_gt7d:stageOutliers,
   opt_out_rate_pct:optOutRate,
   complaint_signals_7d:complaintSignals,
   refund_signals_7d:refundSignals,
   fulfillment_failures_7d:fulfillmentFailures,
   sample_sizes:{opportunities:opps.length,conversations:convs.length,contacts:contacts.length,sla_pairs:slas.length,followups_due:followupDue}
 };

 const thresholds={
   speed_to_lead_median_min:10,
   speed_to_lead_p95_min:15,
   stale_leads_gt24h:0,
   follow_up_completion_rate_pct:95,
   stage_aging_outliers_gt7d:0,
   opt_out_rate_pct:5,
   complaint_signals_7d:0,
   refund_signals_7d:0,
   fulfillment_failures_7d:0
 };

 const breaches=[];
 if(metrics.speed_to_lead_median_min!=null && metrics.speed_to_lead_median_min>thresholds.speed_to_lead_median_min) breaches.push('speed_to_lead_median_min');
 if(metrics.speed_to_lead_p95_min!=null && metrics.speed_to_lead_p95_min>thresholds.speed_to_lead_p95_min) breaches.push('speed_to_lead_p95_min');
 if(metrics.stale_leads_gt24h>thresholds.stale_leads_gt24h) breaches.push('stale_leads_gt24h');
 if(metrics.follow_up_completion_rate_pct<thresholds.follow_up_completion_rate_pct) breaches.push('follow_up_completion_rate_pct');
 if(metrics.stage_aging_outliers_gt7d>thresholds.stage_aging_outliers_gt7d) breaches.push('stage_aging_outliers_gt7d');
 if(metrics.opt_out_rate_pct>thresholds.opt_out_rate_pct) breaches.push('opt_out_rate_pct');
 if(metrics.complaint_signals_7d>thresholds.complaint_signals_7d) breaches.push('complaint_signals_7d');
 if(metrics.refund_signals_7d>thresholds.refund_signals_7d) breaches.push('refund_signals_7d');
 if(metrics.fulfillment_failures_7d>thresholds.fulfillment_failures_7d) breaches.push('fulfillment_failures_7d');

 console.log(JSON.stringify({metrics,thresholds,breaches},null,2));
})();

